import type { Board } from 'chessboard/model/board/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { animatePiece } from 'chessboard/renderers/webgl/base/animation';
import { findPieceFromSquare } from 'chessboard/renderers/webgl/base/pieces/find-piece-from-square';

/**
 * Respond to an illegal move.
 */
export function illegalMove<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  kingInCheck: false | Board.SanSquare,
): void {
  const { state, animationMethods } = instance;

  if (kingInCheck && animationMethods.attackKing) {
    const kingPiece = findPieceFromSquare(state, kingInCheck);

    if (!kingPiece) {
      return;
    }

    animatePiece(instance, {
      animation: animationMethods.attackKing(state, { piece: kingPiece, illegalMove: true }),
      type: WebGLRenderer.Piece.Animation.Type.KingAttack,
      piece: kingPiece,
    });
  }
}
