import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Hide the hover square.
 */
export function hideHoverSquare<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { state, methods, animationMethods } = instance;

  if (animationMethods.hideHoverSquare) {
    animationMethods.hideHoverSquare(state);
  } else {
    methods.hideHoverSquare(state);
  }
}
