import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Close the promotion window.
 */
export function closePromotionWindow<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { state, methods, animationMethods } = instance;

  if (state.promotionWindowAnimation) {
    state.animator.end(state.promotionWindowAnimation);
    state.promotionWindowAnimation = null;
  }

  if (animationMethods.hidePromotionWindow) {
    state.promotionWindowAnimation = animationMethods.hidePromotionWindow(state);

    state.promotionWindowAnimation.onEnd(() => {
      methods.closePromotionWindow(state);

      state.promotionWindowAnimation = null;
    });
  } else {
    methods.closePromotionWindow(state);
  }

  state.isPromotionWindowVisible = false;
}
