import type { Board } from 'chessboard/model/board/types';
import { Constants } from 'chessboard/renderers/webgl/base/constants';
import type { LegacyThemes } from 'chessboard/config/legacy-themes';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { createAnimator } from 'chessboard/renderers/model/animator';

/**
 * Create the WebGL board's base state.
 */
export function createBaseState(
  containerEl: HTMLElement,
  {
    options,
    boardThemes,
    pieceThemes,
  }: {
    options: Board.Options;
    boardThemes: LegacyThemes.BoardStyles;
    pieceThemes: LegacyThemes.PieceStyles;
  },
): WebGLRenderer.State {
  const animator = createAnimator(true);

  return {
    animatedOverPiece: null,
    animatedOverHint: null,
    animator,
    attackedKing: null,
    arrows: {},
    assetsLoaded: false,
    blinkingHighlights: {},
    boardId: options.id || 'webglBoard',
    boardStyle: options.boardStyle,
    boardThemes,
    containerEl,
    customItems: {},
    destroyed: false,
    effects: {},
    fadeSetupAnimation: null,
    flipCoordinates: false,
    highlights: {},
    hints: {},
    hoverSquare: null,
    isBoardFlipped: options.flipped,
    isBoardEnabled: options.enabled,
    isCheckmate: false,
    isPromotionWindowVisible: false,
    options,
    pieceAnimations: {},
    pieces: {},
    pieceStyle: options.pieceStyle,
    pieceThemes,
    pointer: {
      boardPosition: { x: 0, y: 0 },
      down: false,
      downInsideBoard: false,
      event: new Event(''),
      insideBoard: false,
      previousBoardPosition: { x: 0, y: 0 },
      previousViewPosition: { x: 0, y: 0 },
      rightDown: false,
      secondaryDown: false,
      viewPosition: { x: 0, y: 0 },
    },
    promotionWindowAnimation: null,
    selectedPiece: null,
    squareSize: 0,
    viewEl: document.createElement('canvas'),
    viewSize: {
      width: <number>Constants.Board.DefaultWidth,
      height: <number>Constants.Board.DefaultHeight,
    },
    takeover: [],
  };
}
