import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { getFileRankFromSan } from 'chessboard/model/board/get-file-rank-from-san';

/**
 * Find piece position from a SAN square.
 */
export function squareToPiecePosition<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  square: Board.SanSquare,
): WebGLRenderer.BoardPosition {
  const { state, methods } = instance;
  const fileRank = getFileRankFromSan(square);

  return methods.fileRankToPosition(state, fileRank);
}
