import type { Board } from 'model/board/types';
import type { Game } from 'chessboard/model/game/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { addPiece } from 'chessboard/renderers/webgl/base/pieces/add-piece';
import { removePiece } from 'chessboard/renderers/webgl/base/pieces/remove-piece';
import { endAllPiecesAnimation } from 'chessboard/renderers/webgl/base/animation';

/**
 * Load pieces on the board.
 */
export function loadPieces<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    piecesInfo,
    reloadAll,
  }: {
    piecesInfo: Game.Piece.Collection;
    reloadAll?: boolean;
  },
) {
  const { state, methods } = instance;

  endAllPiecesAnimation(state);

  if (reloadAll) {
    Object.values(state.pieces).forEach((piece) => {
      removePiece(instance, { square: <Board.SanSquare>piece.info.square });
    });
  } else {
    // Remove pieces that no longer exist or are different
    Object.values(state.pieces).forEach((piece) => {
      const pieceInfo = piece.info;
      const square = <Board.SanSquare>pieceInfo.square;

      const newPieceInfo = piecesInfo.isDefined(square) ? piecesInfo.get(square) : null;

      if (
        !newPieceInfo ||
        pieceInfo.type !== newPieceInfo.type ||
        pieceInfo.color !== newPieceInfo.color
      ) {
        removePiece(instance, { square });
      }
    });
  }

  // Add the new pieces on the board
  piecesInfo
    .keys()
    .filter((square) => !state.pieces[square])
    .forEach((square) => {
      const piece = piecesInfo.get(square);

      addPiece(instance, piece);
    });

  methods.onPiecesLoaded?.(state);
}
