import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Remove the analysis overlay.
 */
export function removeAnalysisOverlay<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { state, methods } = instance;

  methods.removeAnalysisOverlay(state);
}
