import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Test if the position is inside the board.
 */
export function isPositionInsideBoard<T extends WebGLRenderer.State>(
  state: T,
  position: WebGLRenderer.BoardPosition,
): boolean {
  const { squareSize } = state;

  if (
    position.x >= 0 &&
    position.x <= squareSize * 8 &&
    position.y >= 0 &&
    position.y <= squareSize * 8
  ) {
    return true;
  }

  return false;
}
