import type { Animator } from 'chessboard/renderers/model/animator/types';
import type { KeyedEffect } from 'chessboard/plugins/effects/config/types';
import type { Board } from 'chessboard/model/board/types';
import type { Game } from 'chessboard/model/game/types';
import type { TestElements } from 'src/utils/set-test-data';
import type { LegacyThemes } from 'chessboard/config/legacy-themes';
import type { TextOptions, Types, VisualOrder } from 'chessboard/plugins/custom-items/config/types';
import type { EventEmitterUtil } from '@chesscom/web-ui';
import type { Effects } from 'chessboard/model/effects/types';
import type { Core } from 'chessboard/core/config/types';
import type {
  StartParams,
  ThemeTakeover as Takeover,
} from 'chessboard/plugins/theme-takeover/config/types';

export namespace WebGLRenderer {
  export const PixelRatio = window.devicePixelRatio || 1;

  export interface Params<T extends State> {
    className: string;
    options: Board.Options;
    boardThemes: LegacyThemes.BoardStyles;
    emitter: EventEmitterUtil.EventEmitter;
    pieceThemes: LegacyThemes.PieceStyles;
    containerEl: HTMLElement;
    methods: Methods<T>;
    name: string;
    animationMethods: AnimationMethods<T>;
    testElement?: TestElements;
  }

  export interface Instance<T extends State> {
    state: T;
    methods: Methods<T>;
    animationMethods: AnimationMethods<T>;
    className: string;
    eventListeners: EventListeners;
    frameRequestId: number;
    lastPieceId: number;
  }

  export interface State {
    animator: Animator.API;
    options: Board.Options;
    boardId: string;
    destroyed: boolean;

    flipCoordinates: boolean;

    assetsLoaded: boolean;
    squareSize: number;

    boardStyle: string;
    boardThemes: LegacyThemes.BoardStyles;

    pieceStyle: string;
    pieceThemes: LegacyThemes.PieceStyles;

    containerEl: HTMLElement;
    viewEl: HTMLCanvasElement;
    viewSize: { width: number; height: number };

    isBoardFlipped: boolean;
    isBoardEnabled: boolean;
    isCheckmate: boolean;
    isPromotionWindowVisible: boolean;

    pieces: Piece.Collection<any>;
    selectedPiece: Piece.Model<any> | null;

    animatedOverPiece: Piece.Model<any> | null;
    animatedOverHint: Hint.Model<any> | null;

    fadeSetupAnimation: Animator.Animation.Model | null;
    pieceAnimations: Piece.Animation.Collection;
    promotionWindowAnimation: Animator.Animation.Model | null;

    arrows: Arrow.Collection<any>;
    blinkingHighlights: Highlight.Collection<any>;
    customItems: CustomItem.Collection<any>;
    effects: Effect.Collection<any>;
    highlights: Highlight.Collection<any>;
    hints: Hint.Collection<any>;
    hoverSquare: any;

    attackedKing: Piece.Model<any> | null;

    pointer: PointerState;

    takeover: Array<ThemeTakeover.Model<any>>;
  }

  export interface EventListeners {
    doubleClick?: (event: Event) => void;
    pointerDown?: (event: Event) => void;
    pointerMove?: (event: Event) => void;
    pointerUp?: (event: Event) => void;
    wheel?: (event: WheelEvent) => void;
  }

  export namespace Piece {
    export type Info = Game.Piece.Model;

    export interface Model<T> {
      id: number;
      info: Info;
      obj: T;
    }

    export interface Collection<T> {
      [key: string]: Model<T>;
    }

    export namespace Animation {
      export const enum Type {
        Capture = 'Capture',
        Drag = 'Drag',
        Drop = 'Drop',
        KingAttack = 'KingAttack',
        Move = 'Move',
        Restore = 'Restore',
        Out = 'Out',
        Over = 'Over',
      }

      export interface Collection {
        [key: string]: {
          animation: Animator.Animation.Model;
          type: Type;
        };
      }
    }
  }

  export namespace Arrow {
    export interface Info {
      color: string;
      opacity: number;
      from: Board.FileRank;
      to: Board.FileRank;
      isKnight: boolean;
    }

    export interface Model<T> {
      info: Info;
      obj: T;
    }

    export interface Collection<T> {
      [key: string]: Model<T>;
    }
  }

  export namespace CustomItem {
    export interface Info {
      color?: Game.Node.Marking.Color;
      image?: Game.Node.Marking.ImageOptions;
      frame?: Game.Node.Marking.CustomItem.Frame;
      opacity?: number;
      position: BoardPosition;
      square: Board.SanSquare;
      text?: TextOptions;
      type: Types;
      visualOrder?: VisualOrder.Model;
    }

    export interface Model<T> {
      info: Info;
      obj: T;
    }

    export interface Collection<T> {
      [key: string]: Model<T>;
    }
  }

  export namespace Effect {
    export interface Info {
      position: BoardPosition;
      square: Board.SanSquare;
      type: Game.Node.Marking.Effect.Types;
      effect: KeyedEffect;
    }

    export interface Model<T> {
      animated: boolean;
      info: Info;
      obj: T;
    }

    export interface Collection<T> {
      [key: string]: Model<T>;
    }
  }

  export namespace Highlight {
    export interface Info {
      color: string;
      opacity: number;
      position: BoardPosition;
      square: Board.SanSquare;
      turn?: Game.ColorsAsNumbers;
      type?: string;
    }

    export interface Model<T> {
      info: Info;
      obj: T;
    }

    export interface Collection<T> {
      [key: string]: Model<T>;
    }
  }

  export namespace Hint {
    export interface Info {
      color: string;
      opacity: number;
      position: BoardPosition;
      square: Board.SanSquare;
      turn: Game.ColorsAsNumbers;
      type: Type;
    }

    export interface Model<T> {
      info: Info;
      obj: T;
      activeAnimation?: ItemAnimation.Model;
    }

    export interface Collection<T> {
      [key: string]: Model<T>;
    }

    export const enum Type {
      Move = 'move',
      Capture = 'capture',
    }
  }

  export namespace ThemeTakeover {
    export interface Model<T> {
      info: StartParams;
      obj: T;
    }
  }

  export interface Size {
    width: number;
    height: number;
  }

  export interface BoardPosition {
    x: number;
    y: number;
  }

  export interface PointerState {
    event: Event;
    insideBoard: boolean;

    down: boolean;
    downInsideBoard: boolean;
    rightDown: boolean;
    secondaryDown: boolean;

    viewPosition: Board.Coords;
    boardPosition: BoardPosition;

    previousViewPosition: Board.Coords;
    previousBoardPosition: BoardPosition;
  }

  export namespace ItemAnimation {
    export interface Model {
      animation: Animator.Animation.Model;
      type: Type;
    }

    export const enum Type {
      Show = 'show',
      Hide = 'hide',
      Out = 'out',
      Over = 'over',
    }
  }

  export interface Methods<T extends State> {
    createState: (baseState: State) => T;
    flipBoard: (state: T, shouldFlip: boolean) => void;
    setBoardEnabled?: (state: T, enabled: boolean) => void;
    init: (state: T) => void;
    destroy: (state: T) => void;
    loadAssets: (state: T) => Promise<void>;
    render: (state: T, time: number) => void;
    onWebGLContextLost: (state: T) => void;

    addAnalysisOverlay: (state: T) => void;
    removeAnalysisOverlay: (state: T) => void;

    normalizePointer: (state: T, coords: Board.Coords) => Board.Coords;
    getBoardPosition: (state: T, coords: Board.Coords) => BoardPosition;
    getPieceStyles?: () => LegacyThemes.PieceStyles;
    getViewPosition: (state: T, position: BoardPosition) => Board.Coords;
    getViewAspectRatio: () => number;
    fileRankToPosition: (state: T, fileRank: Board.FileRank) => BoardPosition;
    positionToFileRank: (state: T, position: BoardPosition) => Board.FileRank;
    positionToNearestSquare: (state: T, position: BoardPosition) => BoardPosition;

    createPieceObj: (state: T, pieceInfo: Piece.Info) => any;
    addPiece: (state: T, piece: Piece.Model<any>) => void;
    removePiece: (state: T, piece: Piece.Model<any>) => void;
    setPiecePosition: (piece: Piece.Model<any>, position: BoardPosition) => void;
    fadeInAllPieces: (state: T, duration: number) => Animator.Animation.Model;

    updatePiecesStyle: (state: T, fallback: boolean) => Promise<void>;
    updatePieceVisuals: (state: T, piece: Piece.Model<any>) => void;
    updateViewSize: (state: T, size: Size) => void;

    updateBoardStyle: (state: T) => Promise<void>;

    updateBoardCoordinates: (
      state: T,
      coordinates: {
        flipped: boolean;
        position: Board.CoordinatesPositions;
        colorUpdate?: boolean;
      },
    ) => void;

    createArrowObj: (state: T, arrowInfo: Arrow.Info) => any;
    addArrow: (state: T, arrow: Arrow.Model<any>) => void;
    removeArrow: (state: T, arrow: Arrow.Model<any>) => void;

    createCustomItemObj: (state: T, itemInfo: CustomItem.Info) => any;
    addCustomItem: (state: T, item: CustomItem.Model<any>) => void;
    removeCustomItem: (state: T, item: CustomItem.Model<any>) => void;

    createEffectObj: (state: T, effectInfo: Effect.Info) => any;
    createEffectObjAnimated: (
      state: T,
      effectInfo: Effect.Info,
      translations: Effects.Translations,
      context: Core.Context,
    ) => any;
    addEffect: (state: T, effect: Effect.Model<any>) => void;
    removeEffect: (state: T, effect: Effect.Model<any>) => void;
    fadeOutEffect: (state: T, square: Board.SanSquare) => Promise<void>;

    createHighlightObj: (state: T, highlightInfo: Highlight.Info) => any;
    addHighlight: (state: T, highlight: Highlight.Model<any>) => void;
    removeHighlight: (state: T, highlight: Highlight.Model<any>) => void;

    createCaptureHintObj: (state: T, hintInfo: Hint.Info) => any;
    createMoveHintObj: (state: T, hintInfo: Hint.Info) => any;
    addHint: (state: T, hint: Hint.Model<any>) => void;
    removeHint: (state: T, hint: Hint.Model<any>) => void;

    createHoverSquareObj: (state: T) => any;
    showHoverSquare: (state: T, position: BoardPosition) => void;
    hideHoverSquare: (state: T) => void;

    openPromotionWindow: (
      state: T,
      promotionMove: Game.Move.Model,
    ) => Promise<Game.Piece.Types | undefined>;
    closePromotionWindow: (state: T) => void;

    onPieceDrag?: (state: T, piece: Piece.Model<any>) => void;
    onPieceDrop?: (state: T, piece: Piece.Model<any>) => void;
    onPieceMoved?: (state: T, params: { piece: Piece.Model<any>; square: Board.SanSquare }) => void;
    onPiecesLoaded?: (state: T) => void;
    onPiecesVisualsChanged?: (state: T) => void;

    onMouseDoubleClick?: (state: T) => void;
    onMouseWheel?: (state: T, wheelDelta: number) => boolean;
    onPointerDown?: (state: T) => void;
    onPointerMove?: (state: T) => void;
    onPointerUp?: (state: T) => void;

    createTakeover: (state: T, takeoverInfo: StartParams) => any;
    addTakeover: (state: T, takeover: any) => void;
    endTakeover: (state: T) => void;
    removeTakeover: (state: T) => void;
    removeTakeoverByType: (state: T, takeoverType: Takeover.DirectionOrPercent) => void;
  }

  export interface AnimationMethods<T extends State> {
    init?: (state: T) => void;
    loadAssets?: (state: T) => Promise<void>;

    createHighlightObj?: (state: T, highlightInfo: Highlight.Info) => any;

    createCaptureHintObj?: (state: T, hintInfo: Hint.Info) => any;
    createMoveHintObj?: (state: T, hintInfo: Hint.Info) => any;

    createHoverSquareObj?: (state: T) => any;
    showHoverSquare?: (state: T, position: BoardPosition) => void;
    hideHoverSquare?: (state: T) => void;

    movePiece: (
      state: T,
      params: {
        piece: Piece.Model<any>;
        from: BoardPosition;
        to: BoardPosition;
        castling: boolean;
        capturing: boolean;
      },
    ) => Animator.Animation.Model;

    blinkHighlight: (
      state: T,
      params: { highlight: Highlight.Model<any>; interval: number; times: number },
    ) => Animator.Animation.Model;

    attackKing?: (
      state: T,
      params: { piece: Piece.Model<any>; illegalMove?: boolean },
    ) => Animator.Animation.Model;

    dragPiece?: (state: T, piece: Piece.Model<any>) => Animator.Animation.Model;

    dropPiece?: (
      state: T,
      params: { piece: Piece.Model<any>; to: BoardPosition; capturing?: boolean },
    ) => Animator.Animation.Model;

    capturePiece?: (
      state: T,
      params: { piece: Piece.Model<any>; fromDrop?: boolean },
    ) => Animator.Animation.Model;

    restorePiece?: (state: T, piece: Piece.Model<any>) => Animator.Animation.Model;

    pieceOver?: (
      state: T,
      params: { piece: Piece.Model<any>; pointer: PointerState },
    ) => Animator.Animation.Model;

    pieceOut?: (state: T, piece: Piece.Model<any>) => Animator.Animation.Model;

    hideCustomItem?: (state: T, item: CustomItem.Model<any>) => Animator.Animation.Model;

    showHighlight?: (state: T, highlight: Highlight.Model<any>) => Animator.Animation.Model;

    hideHighlight?: (state: T, highlight: Highlight.Model<any>) => Animator.Animation.Model;

    showHint?: (state: T, hint: Hint.Model<any>) => Animator.Animation.Model;
    hideHint?: (state: T, hint: Hint.Model<any>) => Animator.Animation.Model;
    hintOver?: (state: T, hint: Hint.Model<any>) => Animator.Animation.Model;
    hintOut?: (state: T, hint: Hint.Model<any>) => Animator.Animation.Model;

    showPromotionWindow?: (state: T) => Animator.Animation.Model;
    hidePromotionWindow?: (state: T) => Animator.Animation.Model;
  }
}
