import type { Board } from 'chessboard/model/board/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { animateItem } from 'chessboard/renderers/webgl/base/animation';

/**
 * Remove hints from the board.
 */
export function removeHints<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  squares: Board.SanSquare[],
): void {
  const { state, methods, animationMethods } = instance;
  const { hints } = state;

  squares.forEach((square) => {
    const hint = hints[square];

    if (animationMethods.hideHint) {
      animateItem(state, {
        item: hint,
        type: WebGLRenderer.ItemAnimation.Type.Hide,
        animation: animationMethods.hideHint(state, hint),
        onEnd: () => {
          methods.removeHint(state, hint);
        },
      });
    } else {
      methods.removeHint(state, hint);
    }

    delete hints[square];
  });
}
