/**
 * Easing functions based on Robert Penner's equations.
 * (copied from tween.js: https://github.com/tweenjs/tween.js)
 *
 * http://robertpenner.com/easing
 *
 * t: normalized time
 */

/**
 * Quartic easing in.
 */
export function easeInQuartic(t: number): number {
  return t * t * t * t;
}

/**
 * Quartic easing out.
 */
export function easeOutQuartic(t: number): number {
  return 1 - --t * t * t * t;
}

/**
 * Quartic easing in/out.
 */
export function easeInOutQuartic(t: number): number {
  if ((t *= 2) < 1) {
    return 0.5 * t * t * t * t;
  }

  return -0.5 * ((t -= 2) * t * t * t - 2);
}
