import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Stop the animation of a piece.
 */
export function endPieceAnimation<T extends WebGLRenderer.State>(
  state: T,
  piece: WebGLRenderer.Piece.Model<any>,
): void {
  const { animator, pieceAnimations } = state;
  const animData = pieceAnimations[piece.id];

  if (!animData || animData.animation.ended) {
    return;
  }

  animator.end(animData.animation);
}
