import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { findHintFromFileRank } from 'chessboard/renderers/webgl/base/hints/find-hint-from-file-rank';

/**
 * Find hint from board position.
 */
export function findHintFromPosition<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  position: WebGLRenderer.BoardPosition,
): WebGLRenderer.Hint.Model<any> | null {
  const { state, methods } = instance;
  const fileRank = methods.positionToFileRank(state, position);

  return findHintFromFileRank(state, fileRank);
}
