import type { Animator } from 'chessboard/renderers/model/animator/types';

/**
 * Creates an animation.
 */
export function createAnimation(params: Animator.Animation.Params): Animator.Animation.Model {
  const { data, keyframes, repeat, target, onEnd } = params;

  const animatedProps = getAnimatedProps(keyframes);
  const animatedPropsKeyframes = getAnimatedPropsKeyframes(animatedProps, keyframes);

  const animation: Animator.Animation.Model = {
    animatedProps,
    animatedPropsKeyframes,
    data: { ...data },
    endCallbacks: [],
    ended: false,
    endTime: 0,
    forcedEnd: false,
    frameInfo: {
      deltaTime: 0,
      elapsedInterval: 0,
      elapsedPercentage: 0,
    },
    isTargetHTMLElement: target instanceof HTMLElement,
    onEnd: (callback) => animation.endCallbacks.push(callback),
    params,
    repeatCount: repeat || 1,
    started: false,
    startTime: 0,
    keptAlive: false,
  };

  if (onEnd) {
    animation.endCallbacks.push(onEnd);
  }

  return animation;
}

/**
 * Gather the animated properties.
 */
function getAnimatedProps(keyframes?: Animator.Animation.Keyframes): Animator.AnimatedProps.Model {
  if (!keyframes) {
    return {};
  }

  if (!keyframes[0]) {
    throw new Error('The animation keyframes must contain values at `0` percentage.');
  }

  return { ...keyframes[0] };
}

/**
 * Gather the keyframes for each animated property.
 */
function getAnimatedPropsKeyframes(
  animatedProps: Animator.AnimatedProps.Model,
  keyframes?: Animator.Animation.Keyframes,
): Animator.AnimatedProps.Keyframes {
  if (!keyframes) {
    return {};
  }

  const animatedPropsList = Object.keys(animatedProps);
  const animatedPropsKeyframes: Animator.AnimatedProps.Keyframes = {};

  animatedPropsList.forEach((property) => (animatedPropsKeyframes[property] = []));

  Object.keys(keyframes)
    .sort((a, b) => parseInt(a, 10) - parseInt(b, 10))
    .forEach((key) => {
      animatedPropsList.forEach((property) => {
        if (keyframes[key][property] !== undefined) {
          animatedPropsKeyframes[property].push(parseInt(key, 10));
        }
      });
    });

  return animatedPropsKeyframes;
}
