import { Game } from 'chessboard/model/game/types';
import type { KeyedHighlight } from 'chessboard/plugins/highlights/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';

/**
 * Add highlights to the board.
 */
export function addHighlights<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  highlightsToAdd: KeyedHighlight[],
): void {
  const { state, methods, animationMethods } = instance;
  const { highlights } = state;

  highlightsToAdd.forEach((highlightToAdd) => {
    const { color, opacity, square, turn, type } = highlightToAdd.data;

    if (highlights[square]) {
      methods.removeHighlight(state, highlights[square]);

      delete highlights[square];
    }

    const highlightInfo = {
      color: color || Game.Highlight.Defaults.Color,
      opacity,
      position: squareToPiecePosition(instance, square),
      square,
      turn,
      type,
    };

    const highlight = {
      info: highlightInfo,
      obj:
        animationMethods.createHighlightObj?.(state, highlightInfo) ||
        methods.createHighlightObj(state, highlightInfo),
    };

    methods.addHighlight(state, highlight);

    animationMethods.showHighlight?.(state, highlight);

    highlights[square] = highlight;
  });
}
