import type { ThemeAssets } from 'chessboard/config/theme-assets';
import type { Game } from 'chessboard/model/game/types';
import {
  easeInQuadratic,
  easeOutCubic,
  easeOutQuadratic,
} from 'chessboard/renderers/model/animator/easing';

export namespace ThemeTakeover {
  export namespace Plugin {
    export const Name = 'themeTakeover';
  }

  export enum SwipeDirection {
    Up = 'up',
    Down = 'down',
  }

  export enum SwipePercent {
    Half = 'half',
    Full = 'full',
  }

  export type DirectionOrPercent = SwipeDirection | SwipePercent;

  export type ThemeUrls = {
    board: string;
    pieces: ThemeAssets.PieceAssets2D;
  };

  export type StartParams = {
    themeUrls: ThemeUrls;
    swipeDirection: SwipeDirection;
    swipePercent: SwipePercent;
    automaticSwipeOut: boolean;
    showOverlay: boolean;

    coordinateColors?: ThemeAssets.CoordinateColors;
    swipeDuration?: number;
  };

  export interface API {
    start(startParams: StartParams): void;
    end(): void;
    clear(): void;
  }

  export enum Events {
    StartTakeover = 'StartTakeover',
    EndTakeover = 'EndTakeover',
    ClearTakeover = 'ClearTakeover',
  }
}

export type PiecesCollection = ReturnType<Game.Piece.Collection['getCollection']>;

export const takeoverCssClass = 'takeover';
export const boardPiecesWrapperClass = 'board-pieces-wrapper';
export const swipeInAnimationName = 'takeoverSwipeIn';
export const swipeOutAnimationName = 'takeoverSwipeOut';

export const SwipeMap = {
  [ThemeTakeover.SwipePercent.Full]: {
    percent: 1,
    duration: 800,
    easing: {
      in: easeInQuadratic,
      out: easeOutQuadratic,
    },
  },
  [ThemeTakeover.SwipePercent.Half]: {
    percent: 0.5,
    duration: 400,
    easing: {
      in: easeOutCubic,
      out: easeInQuadratic,
    },
  },
};

export type StartParams = ThemeTakeover.StartParams;
