import type { KeyedArrow } from 'chessboard/plugins/arrows/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Remove arrows from the board.
 */
export function removeArrows<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  arrows: KeyedArrow[],
): void {
  const { state, methods } = instance;

  arrows.forEach((arrow) => {
    const { key } = arrow;

    methods.removeArrow(state, state.arrows[key]);

    delete state.arrows[key];
  });
}
