import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Updates the pieces' visuals.
 */
export function updatePiecesVisuals<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { state, methods } = instance;

  Object.values(state.pieces).forEach((piece) => {
    methods.updatePieceVisuals(state, piece);
  });

  methods.onPiecesVisualsChanged?.(state);
}
