import { isTouchEvent } from 'chessboard/model/dom/is-touch-event';

/**
 * Determine whether or not a DOM event is caused by a secondary button, like right or middle button.
 */
export function isSecondaryButton(event: MouseEvent | PointerEvent | TouchEvent): boolean {
  return isTouchEvent(event) ? false : (<MouseEvent | PointerEvent>event).which > 1;
}
