import type { KeyedCustomItem } from 'chessboard/plugins/custom-items/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Remove custom items from the board.
 */
export function removeCustomItems<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  itemsToRemove: KeyedCustomItem[],
): void {
  const { state, methods, animationMethods } = instance;
  const { customItems } = state;

  itemsToRemove.forEach((itemToRemove) => {
    const {
      data: { square },
    } = itemToRemove;
    const item = customItems[square];

    if (item) {
      if (animationMethods.hideCustomItem && !item.info.frame?.imageAnimated) {
        animationMethods.hideCustomItem(state, item).onEnd(() => {
          methods.removeCustomItem(state, item);
        });
      } else {
        methods.removeCustomItem(state, item);
      }
    }

    delete customItems[square];
  });
}
