import { getXYFromEvent } from 'src/utils/get-xy-from-event';

/**
 * Get XY coordinates from event, relative to top left of board.
 */
export function getBoardXYFromEvent(event: any, boardEl: HTMLElement): object {
  const boardRect = boardEl.getBoundingClientRect();
  const { x, y } = getXYFromEvent(event);

  return {
    boardRect,
    x: x - boardRect.left,
    y: y - boardRect.top,
  };
}
