import type { Animator } from 'chessboard/renderers/model/animator/types';
import { easeLinear } from 'chessboard/renderers/model/animator/easing';

/**
 * Updates the animated properties.
 */
export function updateAnimatedProperties(animation: Animator.Animation.Model): void {
  const { animatedProps, animatedPropsKeyframes, frameInfo, isTargetHTMLElement, params } =
    animation;
  const { keyframes, target } = params;
  const { elapsedPercentage } = frameInfo;
  const easing = params.easing || easeLinear;

  if (!keyframes) {
    return;
  }

  let fromValue: number;
  let toValue: number;

  let fromKeyframe: number;
  let toKeyframe: number;

  let keyframeElapsedInterval: number;

  Object.keys(animatedProps).forEach((property) => {
    // Find the keyframes segment.
    for (let i = 1; i < animatedPropsKeyframes[property].length; i++) {
      fromKeyframe = animatedPropsKeyframes[property][i - 1];
      toKeyframe = animatedPropsKeyframes[property][i];

      if (elapsedPercentage >= fromKeyframe && elapsedPercentage <= toKeyframe) {
        fromValue = keyframes[fromKeyframe][property];
        toValue = keyframes[toKeyframe][property];

        break;
      }
    }

    keyframeElapsedInterval = (elapsedPercentage - fromKeyframe) / (toKeyframe - fromKeyframe);
    keyframeElapsedInterval = easing(keyframeElapsedInterval);

    animatedProps[property] = fromValue + (toValue - fromValue) * keyframeElapsedInterval;

    if (target && !isTargetHTMLElement) {
      target[property] = animatedProps[property];
    }
  });
}
