import type { Core } from 'chessboard/core/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { updatePiecesVisuals } from 'chessboard/renderers/webgl/base/pieces';

/**
 * Change the pieces' style.
 */
export function changePiecesStyle<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  context: Core.Context,
  fallback = false,
): void {
  const { state, methods } = instance;
  const { pieceStyle, themeAssets } = context.options;

  state.pieceStyle = pieceStyle;
  state.options.themeAssets = themeAssets;

  methods.updatePiecesStyle(state, fallback).then(() => {
    if (!state.assetsLoaded) {
      return;
    }

    updatePiecesVisuals(instance);
  });
}
