import type { KeyedHighlight } from 'chessboard/plugins/highlights/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Remove highlights from the board.
 */
export function removeHighlights<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  highlightsToRemove: KeyedHighlight[],
): void {
  const { state, methods, animationMethods } = instance;
  const { highlights } = state;

  highlightsToRemove.forEach((highlightToRemove) => {
    const { square } = highlightToRemove.data;

    const highlight = highlights[square];

    if (animationMethods.hideHighlight) {
      animationMethods.hideHighlight(state, highlight).onEnd(() => {
        methods.removeHighlight(state, highlight);
      });
    } else {
      methods.removeHighlight(state, highlight);
    }

    delete highlights[square];
  });
}
