import type { DragPiece } from 'chessboard/renderers/config/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import {
  animatePiece,
  endPieceAnimation,
  isPieceAnimating,
} from 'chessboard/renderers/webgl/base/animation';
import { findPieceFromSquare } from 'chessboard/renderers/webgl/base/pieces';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';

/**
 * Drag a piece on the board.
 */
export function dragPiece<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  draggedPieceInfo: DragPiece,
): void {
  const { state, methods, animationMethods } = instance;

  let position: WebGLRenderer.BoardPosition | null = null;

  if (draggedPieceInfo.toSquare) {
    position = squareToPiecePosition(instance, draggedPieceInfo.toSquare);
  } else if (draggedPieceInfo.coords) {
    position = methods.getBoardPosition(state, draggedPieceInfo.coords);
  }

  if (!position) {
    return;
  }

  const piece = findPieceFromSquare<T>(state, draggedPieceInfo.square);

  if (!piece) {
    return;
  }

  if (!isPieceAnimating(state, { piece, type: WebGLRenderer.Piece.Animation.Type.Drag })) {
    endPieceAnimation(state, piece);
  }

  methods.setPiecePosition(piece, position);

  if (!state.selectedPiece && animationMethods.dragPiece) {
    animatePiece(instance, {
      animation: animationMethods.dragPiece(state, piece),
      type: WebGLRenderer.Piece.Animation.Type.Drag,
      piece,
    });
  }

  state.selectedPiece = piece;

  methods.onPieceDrag?.(state, piece);
}
