import type { Game } from 'chessboard/model/game/types';

/**
 * Set attributes for the SVG markup.
 */
export function setSVGAttributes(
  svgMarkup: string,
  attrs: { color?: string; opacity?: number; text?: Game.Node.Marking.TextOptions },
): string {
  const itemEl = document.createElement('div');

  itemEl.innerHTML = svgMarkup;

  const svgEl = itemEl.querySelector('svg');

  if (!svgEl) {
    return svgMarkup;
  }

  if (attrs.color) {
    svgEl.style.fill = attrs.color;
  }

  if (attrs.opacity) {
    svgEl.style.opacity = String(attrs.opacity);
  }

  if (attrs.text) {
    const textEl = svgEl.querySelector('text');

    if (textEl) {
      textEl.innerHTML = attrs.text.value;

      textEl.style.fontSize = '0.5rem';
      textEl.style.fontFamily =
        '-apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif';

      if (attrs.text.color) {
        textEl.style.fill = attrs.text.color;
      }
    }
  }

  return svgEl.outerHTML;
}
