import type { Board } from 'chessboard/model/board/types';
import { Constants } from 'chessboard/renderers/webgl/base/constants';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';
import type { Core } from 'chessboard/core/config/types';
import { animateItem } from 'chessboard/renderers/webgl/base/animation';

/**
 * Add hints on the board.
 */
export function addHints<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    context,
    squares,
    type,
  }: {
    context: Core.Context;
    squares: Board.SanSquare[];
    type: WebGLRenderer.Hint.Type;
  },
): void {
  const { state, methods, animationMethods } = instance;
  const { hints } = state;

  squares.forEach((square) => {
    const hintInfo = {
      color: <string>Constants.MoveHint.Color,
      opacity: <number>Constants.MoveHint.Opacity,
      position: squareToPiecePosition(instance, square),
      square,
      turn: context.api.getTurn(),
      type,
    };

    const hintObj =
      hintInfo.type === WebGLRenderer.Hint.Type.Capture
        ? animationMethods.createCaptureHintObj?.(state, hintInfo) ||
          methods.createCaptureHintObj(state, hintInfo)
        : animationMethods.createMoveHintObj?.(state, hintInfo) ||
          methods.createMoveHintObj(state, hintInfo);

    const hint = {
      info: hintInfo,
      obj: hintObj,
      activeAnimation: undefined,
    };

    methods.addHint(state, hint);

    if (animationMethods.showHint) {
      animateItem(state, {
        item: hint,
        type: WebGLRenderer.ItemAnimation.Type.Show,
        animation: animationMethods.showHint(state, hint),
      });
    }

    hints[square] = hint;
  });
}
