export namespace Constants {
  export const enum Board {
    DefaultWidth = 300,
    DefaultHeight = 300,

    DefaultDarkSquareColor = '#000000',
    DefaultLightSquareColor = '#ffffff',
  }

  export const enum AnalysisOverlay {
    Opacity = 0.2,
  }

  export const enum CustomItem {
    Opacity = 0.8,

    // The frame crop ratio based on its size.
    FrameCropRatio = 0.9,
  }

  export const enum Effect {
    // The size ratio based on square size.
    SizeRatio = 0.4,

    // The offset ratio from squares' intersection, based on square size.
    OffsetRatio = 0.44,
  }

  export const enum MoveHint {
    Color = '#000000',
    Opacity = 0.1,

    // The circle radius size ratio based on square size.
    RadiusRatio = 0.16,
  }

  export const enum CaptureHint {
    Color = MoveHint.Color,
    Opacity = MoveHint.Opacity,

    // The circle's outer radius size ratio based on square size.
    OuterRadiusRatio = 0.5,

    // The circle's inner radius size ratio based on square size.
    InnerRadiusRatio = 0.41,
  }

  export const enum SVG {
    // The size of the image used to convert the SVG to a texture.
    ImageSize = 256,
  }
}
