import type { Board } from 'chessboard/model/board/types';
import type { Game } from 'chessboard/model/game/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { swapPiece } from 'chessboard/renderers/webgl/base/pieces';
import { movePieces } from 'chessboard/renderers/webgl/base/pieces/move-pieces';
import { removePiece } from 'chessboard/renderers/webgl/base/pieces/remove-piece';
import { addPiece } from 'chessboard/renderers/webgl/base/pieces/add-piece';
import { endAllPiecesAnimation } from 'chessboard/renderers/webgl/base/animation';
import { isCheckmate } from 'chessboard/model/move/is-checkmate';
import { nodeTargetSquare } from 'api/move/model/node-target-square';

/**
 * Make a piece move.
 */
export function makeMove<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    move,
    attackedKingSquare,
  }: {
    move: Game.Move.Extended;
    attackedKingSquare?: Board.SanSquare;
  },
): void {
  const { state } = instance;
  const { pieces } = state;

  endAllPiecesAnimation(state);

  if (move.drop) {
    addPiece(instance, {
      color: move.color,
      square: nodeTargetSquare(move),
      type: move.drop,
    });

    return;
  }

  state.attackedKing = attackedKingSquare ? pieces[attackedKingSquare] : null;
  state.isCheckmate = isCheckmate(move);

  if (move.EPCapturedSquare) {
    removePiece(instance, {
      captured: true,
      square: move.EPCapturedSquare,
      fromDrop: move.userGeneratedDrop,
    });
  } else if (move.captured) {
    removePiece(instance, {
      captured: true,
      square: move.to,
      fromDrop: move.userGeneratedDrop,
    });
  }

  const moves = [move, move.rookMove].filter(Boolean);

  movePieces(instance, <Game.Move.Extended[]>moves);

  if (move.promotion) {
    const promotedPiece = pieces[move.to];

    swapPiece(instance, { piece: promotedPiece, type: move.promotion });
  }
}
