import type { Animator } from 'chessboard/renderers/model/animator/types';
import { updateAnimatedProperties } from 'chessboard/renderers/model/animator/update-animated-properties';
import { createAnimation } from 'chessboard/renderers/model/animator/create-animation';

/**
 * Create an animation manager.
 */
export function createAnimator(manualUpdate: boolean = false): Animator.API {
  /**
   * The animations currently playing.
   */
  const playingAnimations: Animator.Animation.Model[] = [];

  /**
   * The request id returned by `requestAnimationFrame`.
   */
  let frameRequestId = 0;

  /**
   * Last animation frame time (used to calculate delta time).
   */
  let frameTime = 0;

  return {
    end,
    endAll,
    play,
    playingAnimations,
    playingAnimationsCount: () => playingAnimations.length,
    update,
  };

  /**
   * The animation loop.
   */
  function animationLoop(time: number): void {
    const deltaTime = (time - frameTime) * 0.001;

    playingAnimations.forEach((animation) => {
      if (animation.startTime > time) {
        // `true` when using `repeatDelay`
        return;
      }

      const frameInfo = animation.frameInfo;

      frameInfo.deltaTime = deltaTime;

      if (!animation.started && !onAnimationStart(animation, time)) {
        return;
      }

      if (animation.endTime) {
        // Ignore if animation plays indefinitely.

        frameInfo.elapsedInterval =
          (time - animation.startTime) / (animation.endTime - animation.startTime);

        if (frameInfo.elapsedInterval > 1) {
          frameInfo.elapsedInterval = 1;
        }

        frameInfo.elapsedPercentage = Math.round(frameInfo.elapsedInterval * 100);
      }

      onAnimationUpdate(animation);

      if (animation.endTime && animation.endTime <= time) {
        onAnimationEnd(animation);
      }
    });

    frameTime = time;

    if (playingAnimations.length && !manualUpdate) {
      frameRequestId = requestAnimationFrame(animationLoop);
    }
  }

  /**
   * Ends an animation.
   */
  function end(animation: Animator.Animation.Model): void {
    if (animation.ended || playingAnimations.indexOf(animation) < 0) {
      return;
    }

    animation.frameInfo.elapsedInterval = 1;
    animation.frameInfo.elapsedPercentage = 100;

    onAnimationUpdate(animation);
    onAnimationEnd(animation, true);
  }

  /**
   * End all animations.
   */
  function endAll(): void {
    [...playingAnimations].forEach(end);
  }

  /**
   * Ends the animation playback.
   */
  function onAnimationEnd(animation: Animator.Animation.Model, forcedEnd = false): void {
    const { duration, keepAlive, repeatDelay } = animation.params;

    animation.repeatCount--;
    animation.forcedEnd = forcedEnd;

    if (!forcedEnd && animation.repeatCount > 0 && duration && duration !== Infinity) {
      animation.startTime = animation.endTime + (repeatDelay || 0);
      animation.endTime = animation.startTime + duration;

      return;
    }

    if (!forcedEnd && keepAlive) {
      animation.keptAlive = true;

      return;
    }

    animation.ended = true;
    animation.endCallbacks.forEach((callback) => callback(animation));

    removeAnimation(animation);
  }

  /**
   * Starts playing the animation.
   */
  function onAnimationStart(animation: Animator.Animation.Model, time: number): boolean {
    const { duration, delay, onStart } = animation.params;

    if (!animation.startTime) {
      animation.startTime = time + (delay || 0);

      if (duration && duration !== Infinity) {
        animation.endTime = animation.startTime + duration;
      }
    }

    if (animation.startTime > time) {
      return false;
    }

    animation.started = true;

    onStart?.(animation);

    return true;
  }

  /**
   * Process an animation frame.
   */
  function onAnimationUpdate(animation: Animator.Animation.Model): void {
    const { onUpdate } = animation.params;

    updateAnimatedProperties(animation);

    onUpdate?.(animation);
  }

  /**
   * Plays an animation.
   */
  function play(params: Animator.Animation.Params): Animator.Animation.Model {
    const animation = createAnimation(params);

    playingAnimations.push(animation);

    if (!frameRequestId && !manualUpdate) {
      startAnimationLoop();
    }

    return animation;
  }

  /**
   * Removes an animation.
   */
  function removeAnimation(animation: Animator.Animation.Model): void {
    const animationIndex = playingAnimations.indexOf(animation);

    if (animationIndex >= 0) {
      playingAnimations.splice(animationIndex, 1);
    }

    if (!playingAnimations.length && !manualUpdate) {
      stopAnimationLoop();
    }
  }

  /**
   * Starts the animation loop.
   */
  function startAnimationLoop(): void {
    frameTime = performance.now();
    frameRequestId = requestAnimationFrame(animationLoop);
  }

  /**
   * Stops the animation loop.
   */
  function stopAnimationLoop(): void {
    if (frameRequestId) {
      cancelAnimationFrame(frameRequestId);
    }

    frameRequestId = 0;
  }

  /**
   * Updates an animation frame.
   */
  function update(time: number): void {
    animationLoop(time);
  }
}
