import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Flips the board.
 */
export function flipBoard<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  shouldFlip: boolean,
): void {
  const { state, methods } = instance;

  if (state.isBoardFlipped === shouldFlip) {
    return;
  }

  state.isBoardFlipped = shouldFlip;

  methods.flipBoard(state, shouldFlip);
}
