import { AnimationTypes } from 'chessboard/renderers/config/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Check if the renderer is playing animations.
 */
export function isAnimating<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  animationType?: AnimationTypes,
): boolean {
  const { state } = instance;
  const { animator } = state;

  if (animationType === AnimationTypes.Move) {
    const { pieceAnimations } = state;
    let playingAnimationsCount = 0;

    Object.values(pieceAnimations).forEach((animData) => {
      const { animation, type } = animData;

      if (
        ![
          WebGLRenderer.Piece.Animation.Type.Capture,
          WebGLRenderer.Piece.Animation.Type.Drop,
          WebGLRenderer.Piece.Animation.Type.Move,
          WebGLRenderer.Piece.Animation.Type.Restore,
        ].includes(type)
      ) {
        return;
      }

      if (animation && !animation.ended) {
        playingAnimationsCount++;
      }
    });

    return playingAnimationsCount > 0;
  }

  return animator.playingAnimationsCount() > 0;
}
