import type { Board } from 'model/board/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import {
  animatePiece,
  endPieceAnimation,
  isPieceAnimating,
} from 'chessboard/renderers/webgl/base/animation';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';

/**
 * Drop a piece on the board.
 */
export function dropPiece<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  square: Board.SanSquare,
): void {
  const { state, methods, animationMethods } = instance;
  const { selectedPiece } = state;

  if (!selectedPiece) {
    return;
  }

  endPieceAnimation(state, selectedPiece);

  const position = squareToPiecePosition(instance, square);

  if (
    animationMethods.dropPiece &&
    square === selectedPiece.info.square // rely on `makeMove` to animate the move drop
  ) {
    animatePiece(instance, {
      animation: animationMethods.dropPiece(state, { piece: selectedPiece, to: position }),
      type: WebGLRenderer.Piece.Animation.Type.Drop,
      piece: selectedPiece,
      onEnd: ({ forcedEnd }) => {
        if (forcedEnd || !animationMethods.attackKing || selectedPiece.info.square === square) {
          return;
        }

        // Important: reading `attackedKing` directly from `state` is required,
        // since that is set inside `makeMove` which is called after `dropPiece`.
        if (
          state.attackedKing &&
          !isPieceAnimating(state, {
            piece: state.attackedKing,
            type: WebGLRenderer.Piece.Animation.Type.KingAttack,
          })
        ) {
          animatePiece(instance, {
            animation: animationMethods.attackKing(state, { piece: state.attackedKing }),
            type: WebGLRenderer.Piece.Animation.Type.KingAttack,
            piece: state.attackedKing,
          });
        }
      },
    });
  }

  methods.setPiecePosition(selectedPiece, position);
  methods.onPieceDrop?.(state, selectedPiece);

  state.selectedPiece = null;
}
