import type { KeyedCustomItem } from 'chessboard/plugins/custom-items/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';

/**
 * Add custom items on the board.
 */
export function addCustomItems<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  itemsToAdd: KeyedCustomItem[],
): void {
  const { state, methods } = instance;
  const { customItems } = state;

  itemsToAdd.forEach((itemToAdd) => {
    const { color, frame, image, opacity, square, text, type, visualOrder } = itemToAdd.data;

    const itemInfo = {
      color,
      image,
      frame,
      opacity,
      position: squareToPiecePosition(instance, square),
      square,
      text,
      type,
      visualOrder,
    };

    const item = {
      info: itemInfo,
      obj: methods.createCustomItemObj(state, itemInfo),
    };

    methods.addCustomItem(state, item);

    customItems[square] = item;
  });
}
