import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Find hint based on a SAN square.
 */
export function findHintFromSquare<T extends WebGLRenderer.State>(
  state: T,
  square: Board.SanSquare,
): WebGLRenderer.Hint.Model<any> | null {
  return Object.values(state.hints).find((hint) => hint.info.square === square) ?? null;
}
