import type { Board } from 'chessboard/model/board/types';
import { Game } from 'chessboard/model/game/types';
import type { KeyedBlinkingHighlight } from 'chessboard/plugins/highlights/config/types';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Blink highlights.
 */
export function blinkHighlights<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  highlights: KeyedBlinkingHighlight[],
): void {
  highlights.forEach((highlight) => {
    const {
      data: { square },
    } = highlight;

    blinkHighlight(instance, { blinkInfo: highlight, square });
  });
}

/**
 * Blink a square.
 */
function blinkHighlight<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    blinkInfo,
    square,
  }: {
    blinkInfo: KeyedBlinkingHighlight;
    square: Board.SanSquare;
  },
) {
  const { state, methods, animationMethods } = instance;
  const { blinkingHighlights } = state;
  const { color, opacity, interval, times } = blinkInfo.data;

  if (blinkingHighlights[square]) {
    methods.removeHighlight(state, blinkingHighlights[square]);

    delete blinkingHighlights[square];
  }

  const highlightInfo = {
    color: color || Game.Highlight.Defaults.Color,
    opacity,
    position: squareToPiecePosition(instance, square),
    square: square as Board.SanSquare,
  };

  const highlight = {
    info: highlightInfo,
    obj: methods.createHighlightObj(state, highlightInfo),
  };

  methods.addHighlight(state, highlight);

  animationMethods
    .blinkHighlight(state, {
      interval,
      highlight,
      times,
    })
    .onEnd(() => {
      methods.removeHighlight(state, highlight);

      delete blinkingHighlights[square];
    });

  blinkingHighlights[square] = highlight;

  if (state.options.test) {
    (<any>highlightInfo).testBlinkInfo = { interval, times };
  }
}
