import { paths } from 'chessboard/config/paths';
import { getImportMetaEnvDev } from './import-meta-wrappers';

/**
 * Get the full URL for a WebGL asset. Used by the 2D & 3D boards.
 */
export function getWebglAssetUrl(assetPath: string): string {
  const urlParams = new URLSearchParams(window.location.search);

  if (getImportMetaEnvDev()) {
    return `${paths.webglDataUrlDev}/${assetPath}`;
  } else if (urlParams.get('useLocalAssets')) {
    const baseUrl = window.location.href.replace(window.location.search, '');

    return `${baseUrl}/${paths.webglDataUrlDev}/${assetPath}`;
  }

  if (window[paths.webglAssetPaths] && window[paths.webglAssetPaths][assetPath]) {
    return window[paths.webglAssetPaths][assetPath];
  }

  return `${paths.webglDataUrl}/${assetPath}`;
}
