import type { KeyedEffect } from 'chessboard/plugins/effects/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';
import type { Effects } from 'chessboard/model/effects/types';
import type { Core } from 'chessboard/core/config/types';

/**
 * Add effects on the board.
 */
export function addEffects<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  effectsToAdd: KeyedEffect[],
  translations: Effects.Translations,
  context: Core.Context,
): void {
  const { state, methods } = instance;
  const { effects } = state;

  effectsToAdd.forEach((effectToAdd) => {
    const { square, type, animated } = effectToAdd.data;

    const effectInfo: WebGLRenderer.Effect.Info = {
      position: squareToPiecePosition(instance, square),
      square,
      type,
      effect: effectToAdd,
    };

    const createEffectObj = animated ? methods.createEffectObjAnimated : methods.createEffectObj;
    const effectObject = createEffectObj(state, effectInfo, translations, context);

    const effect = {
      animated: Boolean(animated),
      info: effectInfo,
      obj: effectObject,
    };

    effectObject.forEach((obj) => {
      methods.addEffect(state, { ...effect, obj });
    });

    effects[square] = effect;
  });
}
