import type { Core } from 'chessboard/core/config/types';
import type { Board } from 'chessboard/model/board/types';
import type { Game } from 'chessboard/model/game/types';
import type {
  DragPiece,
  Renderer,
  AnimationTypes,
  AddEffectsData,
} from 'chessboard/renderers/config/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import {
  getCoordsFromSquare,
  getPointerPosition,
  getViewAspectRatio,
  getWebGLCanvas,
  handleWebGLContextLost,
} from 'chessboard/renderers/webgl/base/main';
import { init } from 'chessboard/renderers/webgl/base/main/init';
import { destroy } from 'chessboard/renderers/webgl/base/main/destroy';
import { isAnimating } from 'chessboard/renderers/webgl/base/animation/is-animating';
import { getPieces } from 'chessboard/renderers/webgl/base/pieces';
import { dragPiece } from 'chessboard/renderers/webgl/base/pieces/drag-piece';
import { changePiecesStyle } from 'chessboard/renderers/webgl/base/pieces/change-pieces-style';
import { undoMove } from 'chessboard/renderers/webgl/base/pieces/undo-move';
import { removePiece } from 'chessboard/renderers/webgl/base/pieces/remove-piece';
import { dropPiece } from 'chessboard/renderers/webgl/base/pieces/drop-piece';
import { illegalMove } from 'chessboard/renderers/webgl/base/pieces/illegal-move';
import { loadPieces } from 'chessboard/renderers/webgl/base/pieces/load-pieces';
import { makeMove } from 'chessboard/renderers/webgl/base/pieces/make-move';
import {
  addAnalysisOverlay,
  changeBoardStyle,
  fadeSetup,
  flipBoard,
  setBoardEnabled,
  removeAnalysisOverlay,
  resize,
  setBoardCoordinates,
} from 'chessboard/renderers/webgl/base/board';
import { addArrows, removeArrows } from 'chessboard/renderers/webgl/base/arrows';
import {
  addHighlights,
  blinkHighlights,
  hideHoverSquare,
  removeHighlights,
  showHoverSquare,
} from 'chessboard/renderers/webgl/base/highlights';
import { removeHints } from 'chessboard/renderers/webgl/base/hints/remove-hints';
import { addHints } from 'chessboard/renderers/webgl/base/hints/add-hints';
import {
  closePromotionWindow,
  openPromotionWindow,
} from 'chessboard/renderers/webgl/base/promotion-window';
import { addCustomItems, removeCustomItems } from 'chessboard/renderers/webgl/base/custom-items';
import { addEffects, fadeOutEffect, removeEffects } from 'chessboard/renderers/webgl/base/effects';
import {
  clearTakeover,
  startTakeover,
  endTakeover,
} from 'chessboard/renderers/webgl/base/theme-takeover';
import type { KeyedCustomItem } from 'chessboard/plugins/custom-items/config/types';
import type { KeyedArrow } from 'chessboard/plugins/arrows/config/types';
import type { KeyedEffect } from 'chessboard/plugins/effects/config/types';
import type {
  KeyedBlinkingHighlight,
  KeyedHighlight,
} from 'chessboard/plugins/highlights/config/types';
import type { ThemeTakeover } from 'chessboard/plugins/theme-takeover/config/types';

/**
 * Create a WebGL board renderer instance.
 */
export function createWebGLRendererInstance<T extends WebGLRenderer.State>(
  params: WebGLRenderer.Params<T>,
): Renderer.Model {
  const instance = init(params);

  return {
    addAnalysisOverlay: () => addAnalysisOverlay(instance),
    addArrows: (arrows: KeyedArrow[]) => addArrows(instance, arrows),
    addCaptureHints: (squares: Board.SanSquare[], context) => {
      addHints(instance, { context, squares, type: WebGLRenderer.Hint.Type.Capture });
    },
    addCustomItems: (items: KeyedCustomItem[]) => addCustomItems(instance, items),
    addEffects: ({ effects, translations }: AddEffectsData, context: Core.Context) => {
      addEffects(instance, effects, translations, context);
    },
    addMoveHints: (squares: Board.SanSquare[], context) => {
      addHints(instance, { context, squares, type: WebGLRenderer.Hint.Type.Move });
    },
    addHighlights: (highlights: KeyedHighlight[]) => {
      addHighlights(instance, highlights);
    },
    animationComplete: (animationType: AnimationTypes) => animationType && Promise.resolve(),
    areAssetsLoaded: () => instance.state.assetsLoaded,
    blinkHighlights: (blinkingHighlights: KeyedBlinkingHighlight[]) => {
      blinkHighlights(instance, blinkingHighlights);
    },
    closePromotionWindow: () => closePromotionWindow(instance),
    createRenderer: createWebGLRendererInstance,
    destroy: () => destroy(instance),
    dragPiece: (piece: DragPiece) => dragPiece(instance, piece),
    dropPiece: (square: Board.SanSquare) => dropPiece(instance, square),
    ...params.emitter,
    extendRenderer: () => {},
    fadeSetup: (context) => fadeSetup(instance, context.options.fadeSetup),
    flipBoard: (shouldFlip: boolean) => flipBoard(instance, shouldFlip),
    getCoordsFromSquare: (square: Board.SanSquare) => getCoordsFromSquare(instance, square),
    getPieces: () => getPieces(instance),
    getPieceStyles: instance.methods.getPieceStyles,
    getPointerPosition: ({ event }: { event: MouseEvent }) => getPointerPosition(instance, event),
    getRendererOptions: () => params,
    getBoardContainerAspectRatio: () => getViewAspectRatio(instance),
    getWebGLCanvas: () => getWebGLCanvas(instance),
    handleWebGLContextLost: () => handleWebGLContextLost(instance),
    hideHoverSquare: () => hideHoverSquare(instance),
    illegalMove: (kingInCheck: false | Board.SanSquare) => illegalMove(instance, kingInCheck),
    isAnimating: (animationType?: AnimationTypes) => isAnimating(instance, animationType),
    loadPieces: ({ pieces, reloadAll }: { pieces: Game.Piece.Collection; reloadAll?: boolean }) => {
      loadPieces(instance, { piecesInfo: pieces, reloadAll });
    },
    makeMove: (move: Game.Move.Extended, context: Core.Context) => {
      makeMove(instance, { attackedKingSquare: context.api.isCheck() || undefined, move });
    },
    name: params.name,
    openPromotionWindow: (promotionMove: Game.Move.Model, context: Core.Context) => {
      openPromotionWindow(instance, { context, promotionMove });
    },
    removeAnalysisOverlay: () => removeAnalysisOverlay(instance),
    removeArrows: (arrows: KeyedArrow[]) => removeArrows(instance, arrows),
    removeCustomItems: (customItems: KeyedCustomItem[]) => {
      removeCustomItems(instance, customItems);
    },
    removeEffects: (effects: KeyedEffect[]) => removeEffects(instance, effects),
    fadeOutEffect: (square) => fadeOutEffect(instance, square),
    removeHints: (squares: Board.SanSquare[]) => removeHints(instance, squares),
    removePiece: (square: Board.SanSquare) => removePiece(instance, { square }),
    removeHighlights: (highlights: KeyedHighlight[]) => removeHighlights(instance, highlights),
    resize: () => resize(instance),
    setBoardEnabled: (enabled: boolean) => setBoardEnabled(instance, enabled),
    setCoordinates: (coordinates) => setBoardCoordinates(instance, coordinates),
    showHoverSquare: (square: Board.SanSquare) => showHoverSquare(instance, square),
    undoMove: (move: Game.Move.ExtendedNode, context: Core.Context) => {
      undoMove(instance, { attackedKingSquare: context.api.isCheck() || undefined, move });
    },
    updateBoardImage: (context: Core.Context) => {
      changeBoardStyle(instance, context);
    },
    updatePieceBaseImage: (context: Core.Context, fallback = false) => {
      changePiecesStyle(instance, context, fallback);
    },

    startTakeover: (takeoverInfo: ThemeTakeover.StartParams) => {
      startTakeover(instance, takeoverInfo);
    },
    endTakeover: () => endTakeover(instance),
    clearTakeover: () => clearTakeover(instance),
  };
}
