const rgbaRegex = /^rgba?\((\d+),\s*(\d+),\s*(\d+)(?:,\s*((\d|\.)+))?\)$/;

/**
 * Get a hex color from rgba or rgb.
 */
export function rgbToHex(rgb) {
  if (rgb.search('rgb') === -1) {
    return rgb;
  }

  const matches = rgb.match(rgbaRegex);

  return `#${hexValue(matches[1])}${hexValue(matches[2])}${hexValue(matches[3])}`;
}

/**
 * Get opacity from rgba.
 */
export function rgbaToOpacity(rgba) {
  if (rgba.search('rgba') === -1) {
    return 1;
  }

  return parseFloat(rgba.match(rgbaRegex)[4]);
}

/**
 * Get hex notation.
 */
function hexValue(rgb) {
  return `0${parseInt(rgb, 10).toString(16)}`.slice(-2);
}
