import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Find a piece based on a SAN square.
 */
export function findPieceFromSquare<T extends WebGLRenderer.State>(
  state: T,
  square: Board.SanSquare,
): WebGLRenderer.Piece.Model<any> | null {
  const foundPiece = Object.values(state.pieces).find((piece) => {
    if (piece.info.square === square) {
      return true;
    }

    return false;
  });

  return foundPiece || null;
}
