import { ThemeTakeover } from 'chessboard/plugins/theme-takeover/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Starts theme takeover
 */
export function startTakeover<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  takeoverInfo: ThemeTakeover.StartParams,
): void {
  const { state, methods } = instance;

  if (takeoverInfo.swipePercent === ThemeTakeover.SwipePercent.Full) {
    methods.removeTakeover(state);
  } else if (takeoverInfo.swipePercent === ThemeTakeover.SwipePercent.Half) {
    methods.removeTakeoverByType(state, takeoverInfo.swipeDirection);
    methods.removeTakeoverByType(state, ThemeTakeover.SwipePercent.Full);
  }

  const takeoverObject = methods.createTakeover(state, takeoverInfo);
  methods.addTakeover(state, takeoverObject);

  state.takeover.push({
    info: takeoverInfo,
    obj: takeoverObject,
  });
}
