import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { addEventListeners } from 'chessboard/renderers/webgl/base/listeners/add-event-listeners';
import { addToWindow } from 'utils/add-to-window';
import { createBaseState, loadAssets, updateLoop } from 'chessboard/renderers/webgl/base/main';
import { setTestData, TestElements, TestKeys } from 'utils/set-test-data';
import { Core } from 'chessboard/core/config/types';

/**
 * Initialize the WebGL renderer instance.
 */
export function init<T extends WebGLRenderer.State>(
  params: WebGLRenderer.Params<T>,
): WebGLRenderer.Instance<T> {
  const {
    animationMethods,
    boardThemes,
    className,
    containerEl,
    options,
    methods,
    name,
    pieceThemes,
    testElement,
  } = params;

  const state = methods.createState(
    createBaseState(containerEl, { boardThemes, options, pieceThemes }),
  );

  const instance = {
    animationMethods,
    className,
    eventListeners: {},
    frameRequestId: 0,
    lastPieceId: 0,
    methods,
    name,
    state,
  };

  methods.init(state);
  animationMethods.init?.(state);

  state.hoverSquare = animationMethods.createHoverSquareObj
    ? animationMethods.createHoverSquareObj(state)
    : methods.createHoverSquareObj(state);

  loadAssets(instance).then(() => {
    params.emitter.emit(Core.InstanceEvents.WebGLAssetsInitialized, {
      type: Core.InstanceEvents.WebGLAssetsInitialized,
    });
  });
  addEventListeners(instance);

  containerEl.classList.add(className);

  onAnimatedFrameReceived(performance.now());

  if (options.test) {
    setupTestData(state, testElement);
  }

  return instance;

  /**
   * Call the next loop.
   */
  function onAnimatedFrameReceived(time: number): void {
    instance.frameRequestId = requestAnimationFrame(onAnimatedFrameReceived);

    updateLoop(instance, time);
  }
}

/**
 * Add neccessary data for testing.
 */
function setupTestData<T extends WebGLRenderer.State>(state: T, testElement?: TestElements): void {
  setTestData(state.containerEl, {
    [TestKeys.Element]: testElement || TestElements.Board,
  });

  if (testElement === TestElements.SiblingBoard) {
    addToWindow({ webglSiblingBoardState: state });
  } else {
    addToWindow({ webglBoardState: state });
  }
}
