import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { endPieceAnimation } from 'chessboard/renderers/webgl/base/animation';
import { getBoardXYFromEvent } from 'utils/get-board-xy-from-event';
import { isPositionInsideBoard } from 'chessboard/renderers/webgl/base/utils/is-position-inside-board';
import { isRightButton } from 'chessboard/model/dom/is-right-button';
import { isSecondaryButton } from 'chessboard/model/dom/is-secondary-button';

/**
 * On pointer down.
 */
export function onPointerDown<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  event: Event,
): void {
  const { state, methods } = instance;
  const { animatedOverPiece, containerEl, pointer } = state;

  const coords = <Board.Coords>getBoardXYFromEvent(event, containerEl);

  pointer.event = event;

  const isRightDown = isRightButton(event as MouseEvent);

  if (!state.isBoardEnabled && !isRightDown) {
    return;
  }

  pointer.viewPosition = methods.normalizePointer(state, coords);
  pointer.boardPosition = methods.getBoardPosition(state, pointer.viewPosition);

  pointer.down = true;
  pointer.secondaryDown = isSecondaryButton(event as MouseEvent);
  pointer.rightDown = isRightDown;

  pointer.insideBoard = isPositionInsideBoard(state, pointer.boardPosition);
  pointer.downInsideBoard = pointer.insideBoard;

  methods.onPointerDown?.(state);

  if (animatedOverPiece) {
    endPieceAnimation(state, animatedOverPiece);

    state.animatedOverPiece = null;
  }

  pointer.previousViewPosition = pointer.viewPosition;
  pointer.previousBoardPosition = pointer.boardPosition;
}
