import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { findHintFromSquare } from 'chessboard/renderers/webgl/base/hints/find-hint-from-square';
import { getSanFromFileRank } from 'chessboard/model/board/get-san-from-file-rank';

/**
 * Find hint based on file/rank coordinates.
 */
export function findHintFromFileRank<T extends WebGLRenderer.State>(
  state: T,
  fileRank: Board.FileRank,
): WebGLRenderer.Hint.Model<any> | null {
  const square = getSanFromFileRank(fileRank);

  if (square) {
    return findHintFromSquare(state, square);
  }

  return null;
}
