import type { Core } from 'chessboard/core/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Change the board's style.
 */
export function changeBoardStyle<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  context: Core.Context,
): void {
  const { state, methods } = instance;
  const { coordinates, flipped } = state.options;
  const { boardStyle, themeAssets } = context.options;

  state.boardStyle = boardStyle;
  state.options.themeAssets = themeAssets;

  methods.updateBoardStyle(state);
  methods.updateBoardCoordinates(state, { colorUpdate: true, flipped, position: coordinates });
}
