import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Check if a piece is playing an animation.
 */
export function isPieceAnimating<T extends WebGLRenderer.State>(
  state: T,
  {
    piece,
    type,
  }: {
    piece?: WebGLRenderer.Piece.Model<any>;
    type?: WebGLRenderer.Piece.Animation.Type;
  },
): boolean {
  const { pieceAnimations } = state;

  if (piece) {
    const animData = pieceAnimations[piece.id];

    if (!animData || animData.animation.ended) {
      return false;
    }

    if (type && type !== animData.type) {
      return false;
    }

    return true;
  } else if (type) {
    const animations = Object.values(pieceAnimations);

    for (let i = 0; i < animations.length; i++) {
      if (animations[i].type === type) {
        return true;
      }
    }

    return false;
  }

  return false;
}
