import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * End all pieces' animation.
 */
export function endAllPiecesAnimation<T extends WebGLRenderer.State>(
  state: T,
  type?: WebGLRenderer.Piece.Animation.Type,
): void {
  const { animator, pieceAnimations } = state;

  Object.keys(pieceAnimations).forEach((key) => {
    const animData = pieceAnimations[key];

    if (type && type !== animData.type) {
      return;
    }

    animator.end(animData.animation);

    delete pieceAnimations[key];
  });
}
