import type { Animator } from 'chessboard/renderers/model/animator/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Animate a piece.
 */
export function animatePiece<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    piece,
    type,
    animation,
    onEnd,
  }: {
    piece: WebGLRenderer.Piece.Model<any>;
    type: WebGLRenderer.Piece.Animation.Type;
    animation: Animator.Animation.Model;
    onEnd?: Animator.Animation.Callback;
  },
): void {
  const { state } = instance;
  const { animator, pieceAnimations } = state;

  if (pieceAnimations[piece.id] && !pieceAnimations[piece.id].animation.ended) {
    animator.end(pieceAnimations[piece.id].animation);
  }

  pieceAnimations[piece.id] = { animation, type };

  animation.onEnd((endedAnimation) => {
    onEnd?.(endedAnimation);

    if (pieceAnimations[piece.id] && pieceAnimations[piece.id].animation === endedAnimation) {
      delete pieceAnimations[piece.id];
    }
  });
}
