import { getFileRankFromSan } from 'chessboard/model/board/get-file-rank-from-san';
import { getArrowColor } from 'chessboard/model/arrows/get-arrow-color';
import type { KeyedArrow } from 'chessboard/plugins/arrows/config/types';
import { rgbToHex, rgbaToOpacity } from 'utils/colors/convert-color';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Add arrows on the board.
 */
export function addArrows<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  arrows: KeyedArrow[],
): void {
  const { state, methods } = instance;
  const { options } = state;

  arrows.forEach((arrow) => {
    const { data, key } = arrow;
    const { color, from, opacity, to } = data;

    if (state.arrows[key]) {
      methods.removeArrow(state, state.arrows[key]);

      delete state.arrows[key];
    }

    const fromFileRank = getFileRankFromSan(from);
    const toFileRank = getFileRankFromSan(to);

    const fromFileDiff = Math.abs(fromFileRank.file - toFileRank.file);
    const fromRankDiff = Math.abs(fromFileRank.rank - toFileRank.rank);

    const isKnight =
      (fromFileDiff === 1 && fromRankDiff === 2) || (fromFileDiff === 2 && fromRankDiff === 1);

    const arrowColor = getArrowColor(color, options.arrowColors);

    const arrowInfo = {
      color: rgbToHex(arrowColor),
      from: fromFileRank,
      isKnight,
      to: toFileRank,
      opacity: opacity || rgbaToOpacity(arrowColor),
    };

    const arrowState = {
      info: arrowInfo,
      obj: methods.createArrowObj(state, arrowInfo),
    };

    methods.addArrow(state, arrowState);

    state.arrows[key] = arrowState;
  });
}
