import type { Board } from 'chessboard/model/board/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import {
  animateItem,
  animatePiece,
  endItemAnimation,
  endPieceAnimation,
  isPieceAnimating,
} from 'chessboard/renderers/webgl/base/animation';
import { findPieceFromPosition } from 'chessboard/renderers/webgl/base/pieces/find-piece-from-position';
import { findHintFromPosition } from 'chessboard/renderers/webgl/base/hints/find-hint-from-position';
import { getBoardXYFromEvent } from 'utils/get-board-xy-from-event';
import { isPositionInsideBoard, positionToSquare } from 'chessboard/renderers/webgl/base/utils';

/**
 * On pointer move.
 */
export function onPointerMove<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  event: Event,
): void {
  const { state, methods, animationMethods } = instance;
  const { containerEl, pointer } = state;

  const coords = <Board.Coords>getBoardXYFromEvent(event, containerEl);

  pointer.event = event;

  pointer.previousViewPosition = pointer.viewPosition;
  pointer.previousBoardPosition = pointer.boardPosition;

  pointer.viewPosition = methods.normalizePointer(state, coords);
  pointer.boardPosition = methods.getBoardPosition(state, pointer.viewPosition);

  pointer.insideBoard = isPositionInsideBoard(state, pointer.boardPosition);

  methods.onPointerMove?.(state);

  if (!state.isBoardEnabled) {
    return;
  }

  if (animationMethods.pieceOver) {
    doPieceOverAnimation(instance, pointer);
  }

  if (animationMethods.hintOver) {
    doHintOverAnimation(instance, pointer);
  }
}

/**
 * Handles the piece animations for pointer hovering.
 */
function doPieceOverAnimation<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  pointer: WebGLRenderer.PointerState,
): void {
  const { state, animationMethods } = instance;
  const { animatedOverPiece, selectedPiece } = state;

  const overPiece = findPieceFromPosition(instance, pointer.boardPosition);

  if (
    animatedOverPiece &&
    animatedOverPiece !== overPiece &&
    isPieceAnimating(state, {
      piece: animatedOverPiece,
      type: WebGLRenderer.Piece.Animation.Type.Over,
    })
  ) {
    endPieceAnimation(state, animatedOverPiece);

    if (animationMethods.pieceOut) {
      animatePiece(instance, {
        animation: animationMethods.pieceOut(state, animatedOverPiece),
        type: WebGLRenderer.Piece.Animation.Type.Out,
        piece: animatedOverPiece,
      });
    }

    state.animatedOverPiece = null;
  }

  if (selectedPiece && selectedPiece === overPiece) {
    return;
  }

  if (overPiece && !isPieceAnimating(state, { piece: overPiece })) {
    const previousSquare = positionToSquare(instance, pointer.previousBoardPosition);
    const currentSquare = positionToSquare(instance, pointer.boardPosition);

    if (previousSquare === currentSquare) {
      // Pointer was already in (piece dropped), so ignore piece hovering.
      return;
    }

    state.animatedOverPiece = overPiece;

    if (animationMethods.pieceOver) {
      animatePiece(instance, {
        animation: animationMethods.pieceOver(state, { piece: overPiece, pointer }),
        type: WebGLRenderer.Piece.Animation.Type.Over,
        piece: overPiece,
        onEnd: () => (state.animatedOverPiece = null),
      });
    }
  }
}

/**
 * Handles the hint animations for pointer hovering.
 */
function doHintOverAnimation<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  pointer: WebGLRenderer.PointerState,
): void {
  const { state, animationMethods } = instance;
  const { animatedOverHint } = state;

  const overHint = findHintFromPosition(instance, pointer.boardPosition);

  if (animatedOverHint && animatedOverHint !== overHint) {
    endItemAnimation(state, animatedOverHint);

    if (animationMethods.hintOut) {
      animateItem(state, {
        item: animatedOverHint,
        type: WebGLRenderer.ItemAnimation.Type.Out,
        animation: animationMethods.hintOut(state, animatedOverHint),
      });
    }

    state.animatedOverHint = null;
  }

  if (!overHint) {
    return;
  }

  if (
    animationMethods.hintOver &&
    overHint.activeAnimation?.type !== WebGLRenderer.ItemAnimation.Type.Over
  ) {
    animateItem(state, {
      item: overHint,
      type: WebGLRenderer.ItemAnimation.Type.Over,
      animation: animationMethods.hintOver(state, overHint),
      onEnd: () => (state.animatedOverHint = null),
    });

    state.animatedOverHint = overHint;
  }
}
