import type { KeyedEffect } from 'chessboard/plugins/effects/config/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Remove effects from the board.
 */
export function removeEffects<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  effectsToAdd: KeyedEffect[],
): void {
  const { state, methods } = instance;
  const { effects } = state;

  effectsToAdd.forEach((effectToAdd) => {
    const { square } = effectToAdd.data;

    effects[square]?.obj.forEach((obj) => methods.removeEffect(state, { ...effects[square], obj }));

    delete effects[square];
  });
}
