import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import type { Game } from 'model/game/types';

/**
 * Get a collection of concise piece objects.
 */
export function getPieces<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): Game.Piece.ConciseObject {
  const { state } = instance;

  return Object.keys(state.pieces).reduce(
    (acc, key) => {
      acc[key] = {
        color: state.pieces[key].info.color,
        type: state.pieces[key].info.type as Game.Piece.Types,
      };

      return acc;
    },
    <Game.Piece.ConciseObject>{},
  );
}
