import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import type JCE from '@chesscom/js-chess-engine';

/**
 * Replace a piece with another.
 */
export function swapPiece<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    piece,
    type,
  }: {
    piece: WebGLRenderer.Piece.Model<any>;
    type?: JCE.PieceSignature;
  },
): void {
  const { state, methods } = instance;

  if (type) {
    piece.info.type = type;
  }

  methods.updatePieceVisuals(state, piece);
}
