import type JCE from '@chesscom/js-chess-engine';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Add effects on the board.
 */
export function fadeOutEffect<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  square: JCE.SanSquare,
): Promise<void> {
  const { state, methods } = instance;
  return methods.fadeOutEffect(state, square);
}
