import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { updatePiecesVisuals } from 'chessboard/renderers/webgl/base/pieces';

/**
 * Load the assets.
 */
export function loadAssets<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): Promise<void> {
  const { state, methods, animationMethods } = instance;

  return Promise.all([methods.loadAssets(state), animationMethods.loadAssets?.(state)]).then(() => {
    if (state.destroyed) {
      return;
    }

    state.assetsLoaded = true;

    updatePiecesVisuals(instance);

    state.containerEl.appendChild(state.viewEl);
  });
}
