import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Handle the WebGL context lost.
 */
export function handleWebGLContextLost<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { state, methods } = instance;
  const { viewEl } = state;

  const newViewEl = <HTMLCanvasElement>viewEl.cloneNode();

  viewEl.replaceWith(newViewEl);

  state.viewEl = newViewEl;

  methods.onWebGLContextLost(state);
}
