import type { Markings } from 'chessboard/plugins/markings/config/types';

export namespace CustomItems {
  export interface API {
    getDefaultStarColor(): string;
  }

  export namespace Plugin {
    export const Name = 'custom-items';
  }

  export enum Classes {
    Root = 'custom-item',
  }
}

export const CustomItemType = 'customItem';

export type CustomItemParams = {
  data: CustomItemData;
  type: typeof CustomItemType;
};

export type CustomItem = Markings.Model & CustomItemParams;

export type KeyedCustomItem = Markings.KeyedModel & CustomItemParams;

export type CustomItemData = Markings.WithSquare &
  Partial<Markings.WithOpacity> &
  Partial<Markings.WithColor> & {
    image?: ImageOptions;
    text?: TextOptions;
    type: Types;
    visualOrder?: VisualOrder.Model;
    frame?: Frame;
    removalClass?: string;
    removalSound?: string;
    removalTimeout?: number;
  };

export interface ImageOptions {
  percentOfSquare?: number;
  url: string;
}

export interface TextOptions {
  color?: string;
  value: string;
}

export interface Frame {
  imageURL: string;
  imageAnimated?: boolean;
  positionRatioX: number;
  positionRatioY: number;
  widthRatio: number;
  heightRatio: number;
}

export namespace VisualOrder {
  export interface Model {
    position?: Positions;
    target: Targets;
  }

  export const enum Targets {
    Arrows = 'arrows',
    Effects = 'effects',
    Pieces = 'pieces',
  }

  export const enum Positions {
    Above = 'above',
    Below = 'below',
  }
}

export enum Types {
  Image = 'Image',
  Star = 'Star',
  TextBox = 'TextBox',
}
