import { Pointerdown, Pointerup, Pointermove } from 'chessboard/model/dom/get-pointer-events';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { onMouseDoubleClick } from 'chessboard/renderers/webgl/base/listeners/on-mouse-double-click';
import { onMouseWheel } from 'chessboard/renderers/webgl/base/listeners/on-mouse-wheel';
import { onPointerDown } from 'chessboard/renderers/webgl/base/listeners/on-pointer-down';
import { onPointerMove } from 'chessboard/renderers/webgl/base/listeners/on-pointer-move';
import { onPointerUp } from 'chessboard/renderers/webgl/base/listeners/on-pointer-up';

/**
 * Add event listeners.
 */
export function addEventListeners<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { eventListeners, state, methods } = instance;
  const { containerEl } = state;

  eventListeners.pointerDown = (event) => onPointerDown(instance, event);
  eventListeners.pointerMove = (event) => onPointerMove(instance, event);
  eventListeners.pointerUp = (event) => onPointerUp(instance, event);

  containerEl.addEventListener(Pointerdown, eventListeners.pointerDown);
  document.addEventListener(Pointermove, eventListeners.pointerMove);
  document.addEventListener(Pointerup, eventListeners.pointerUp);

  if (methods.onMouseDoubleClick) {
    eventListeners.doubleClick = (event) => onMouseDoubleClick(instance, event);

    containerEl.addEventListener('dblclick', eventListeners.doubleClick);
  }

  if (methods.onMouseWheel) {
    eventListeners.wheel = (event) => onMouseWheel(instance, event);

    containerEl.addEventListener('wheel', eventListeners.wheel);
  }
}
