import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { findPieceFromSquare } from 'chessboard/renderers/webgl/base/pieces';
import { getSanFromFileRank } from 'chessboard/model/board/get-san-from-file-rank';

/**
 * Find a piece based on file/rank coordinates.
 */
export function findPieceFromFileRank<T extends WebGLRenderer.State>(
  state: T,
  fileRank: Board.FileRank,
): WebGLRenderer.Piece.Model<any> | null {
  const square = getSanFromFileRank(fileRank);

  if (square) {
    return findPieceFromSquare(state, square);
  }

  return null;
}
