import { Core } from 'chessboard/core/config/types';
import type { Game } from 'chessboard/model/game/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { createCoreEvent } from 'chessboard/core/model/create-core-event';

/**
 * Open the promotion window.
 */
export function openPromotionWindow<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    promotionMove,
    context,
  }: {
    promotionMove: Game.Move.Model;
    context: Core.Context;
  },
): void {
  const { state, methods, animationMethods } = instance;

  if (state.promotionWindowAnimation) {
    state.animator.end(state.promotionWindowAnimation);
    state.promotionWindowAnimation = null;
  }

  methods.openPromotionWindow(state, promotionMove).then((pieceType) => {
    if (!state.isPromotionWindowVisible) {
      return;
    }

    if (pieceType) {
      context.run(
        createCoreEvent(Core.BoardEvents.PromotionPiecePointerdown, { piece: pieceType }),
      );
    } else {
      context.run(createCoreEvent(Core.BoardEvents.PromotionAreaClosePointerdown));
    }
  });

  if (animationMethods.showPromotionWindow) {
    state.promotionWindowAnimation = animationMethods.showPromotionWindow(state);
    state.promotionWindowAnimation.onEnd(() => (state.promotionWindowAnimation = null));
  }

  state.isPromotionWindowVisible = true;
}
