import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { getSanFromFileRank } from 'chessboard/model/board/get-san-from-file-rank';

/**
 * Converts the board position to a SAN square.
 */
export function positionToSquare<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  position: WebGLRenderer.BoardPosition,
): Board.SanSquare | null {
  const { state, methods } = instance;
  const fileRank = methods.positionToFileRank(state, position);

  return getSanFromFileRank(fileRank);
}
