import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * The update loop.
 */
export function updateLoop<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  time: number,
): void {
  const { state, methods } = instance;

  state.animator.update(time);

  methods.render(state, time);
}
