import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { findPieceFromFileRank } from 'chessboard/renderers/webgl/base/pieces/find-piece-from-file-rank';

/**
 * Find piece from board position.
 */
export function findPieceFromPosition<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  position: WebGLRenderer.BoardPosition,
): WebGLRenderer.Piece.Model<any> | null {
  const { state, methods } = instance;
  const fileRank = methods.positionToFileRank(state, position);

  return findPieceFromFileRank(state, fileRank);
}
