import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Converts the position to square percentage (from 0 to 100).
 */
export function positionToSquarePercentage(
  position: WebGLRenderer.BoardPosition,
  squareSize: number,
): WebGLRenderer.BoardPosition {
  const positionX = Math.floor(position.x);
  const positionY = Math.floor(position.y);

  const squarePosition = {
    left: Math.floor(positionX / squareSize) * squareSize,
    top: Math.floor(positionY / squareSize) * squareSize,
  };

  const positionInsideSquare = {
    left: positionX - squarePosition.left,
    top: positionY - squarePosition.top,
  };

  return {
    x: Math.floor((positionInsideSquare.left / squareSize) * 100),
    y: Math.floor((positionInsideSquare.top / squareSize) * 100),
  };
}
