import type { Board } from 'model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { generatePieceId } from 'chessboard/renderers/webgl/base/pieces';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';

/**
 * Add a piece on the board.
 */
export function addPiece<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  pieceInfo: WebGLRenderer.Piece.Info,
): WebGLRenderer.Piece.Model<any> {
  const { state, methods } = instance;

  const piece: WebGLRenderer.Piece.Model<any> = {
    id: generatePieceId(instance),
    info: pieceInfo,
    obj: methods.createPieceObj(state, pieceInfo),
  };

  const piecePosition = squareToPiecePosition(instance, <Board.SanSquare>pieceInfo.square);

  if (state.assetsLoaded) {
    methods.updatePieceVisuals(state, piece);
  }

  methods.setPiecePosition(piece, piecePosition);
  methods.addPiece(state, piece);

  state.pieces[<Board.SanSquare>pieceInfo.square] = piece;

  return piece;
}
