import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Set board coordinates.
 */
export function setBoardCoordinates<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    position,
    flipped,
  }: {
    position: Board.CoordinatesPositions;
    flipped: boolean;
  },
): void {
  const { state, methods } = instance;

  methods.updateBoardCoordinates(state, { flipped, position });
}
