import type { Animator } from 'chessboard/renderers/model/animator/types';
import type { Board } from 'chessboard/model/board/types';
import { Game } from 'chessboard/model/game/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import {
  animatePiece,
  endAllPiecesAnimation,
  isPieceAnimating,
} from 'chessboard/renderers/webgl/base/animation';
import { isCapture } from 'chessboard/model/move/is-capture';
import { isCastle } from 'chessboard/model/move/is-castle';
import { squareToPiecePosition } from 'chessboard/renderers/webgl/base/utils';
import { nodeTargetSquare } from 'api/move/model/node-target-square';

/**
 * Move a piece from one square to another.
 */
export function movePieces<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  moves: Game.Move.Extended[],
): void {
  const { state, methods, animationMethods } = instance;
  const { attackedKing, pieces, pointer } = state;

  let castling = isCastle(moves[0]);
  const capturing = isCapture(moves[0]);
  const movedPieces: WebGLRenderer.Piece.Collection<any> = {};

  if (!castling && moves.length === 2) {
    // check for castling undo
    const piece1 = pieces[<Board.SanSquare>moves[0].from];
    const piece2 = pieces[<Board.SanSquare>moves[1].from];

    if (piece1.info.type === Game.Piece.Types.King && piece2.info.type === Game.Piece.Types.Rook) {
      castling = true;
    }
  }

  moves.forEach((move) => {
    const moveTo = nodeTargetSquare(move);

    if (!moveTo) {
      return;
    }

    const piece = pieces[<Board.SanSquare>move.from];
    const fromPosition = squareToPiecePosition(instance, <Board.SanSquare>move.from);
    const toPosition = squareToPiecePosition(instance, moveTo);

    let animation: Animator.Animation.Model | null = null;
    let animationType = WebGLRenderer.Piece.Animation.Type.Move;

    if (move.userGeneratedDrop && animationMethods.dropPiece) {
      methods.setPiecePosition(piece, pointer.boardPosition);

      animation = animationMethods.dropPiece(state, { capturing, piece, to: toPosition });
      animationType = WebGLRenderer.Piece.Animation.Type.Drop;
    } else if (!move.userGeneratedDrop && move.animate && move.from !== moveTo) {
      animation = animationMethods.movePiece(state, {
        capturing,
        castling,
        from: fromPosition,
        piece,
        to: toPosition,
      });
    }

    if (animation) {
      animatePiece(instance, {
        animation,
        type: animationType,
        piece,
        onEnd: ({ forcedEnd }) => {
          methods.onPieceMoved?.(state, { piece, square: moveTo });

          if (forcedEnd || !animationMethods.attackKing) {
            return;
          }

          if (
            move.san && // `move.san` is used to check for main move since one of the moves can be a rook move.
            attackedKing &&
            !isPieceAnimating(state, {
              piece: attackedKing,
              type: WebGLRenderer.Piece.Animation.Type.KingAttack,
            })
          ) {
            animatePiece(instance, {
              animation: animationMethods.attackKing(state, { piece: attackedKing }),
              type: WebGLRenderer.Piece.Animation.Type.KingAttack,
              piece: attackedKing,
            });
          }
        },
      });
    } else {
      methods.setPiecePosition(piece, toPosition);
      methods.onPieceMoved?.(state, { piece, square: moveTo });
    }

    if (
      !attackedKing &&
      isPieceAnimating(state, { type: WebGLRenderer.Piece.Animation.Type.KingAttack })
    ) {
      endAllPiecesAnimation(state, WebGLRenderer.Piece.Animation.Type.KingAttack);
    }

    if (move.from !== moveTo) {
      piece.info.square = moveTo;

      movedPieces[<Board.SanSquare>move.from] = piece;
    }
  });

  Object.keys(movedPieces).forEach((from) => {
    const piece = movedPieces[from];
    const oldPiece = pieces[from];

    pieces[<Board.SanSquare>piece.info.square] = piece;

    if (piece.info.type === oldPiece.info.type && piece.info.color === oldPiece.info.color) {
      delete pieces[from];
    }
  });
}
