import { Pointerdown, Pointerup, Pointermove } from 'chessboard/model/dom/get-pointer-events';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Remove event listeners.
 */
export function removeEventListeners<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { eventListeners, state } = instance;
  const { containerEl } = state;

  if (eventListeners.pointerDown) {
    containerEl.removeEventListener(Pointerdown, eventListeners.pointerDown);
  }

  if (eventListeners.pointerMove) {
    document.removeEventListener(Pointermove, eventListeners.pointerMove);
  }

  if (eventListeners.pointerUp) {
    document.removeEventListener(Pointerup, eventListeners.pointerUp);
  }

  if (eventListeners.doubleClick) {
    containerEl.removeEventListener('dblclick', eventListeners.doubleClick);
  }

  if (eventListeners.wheel) {
    containerEl.removeEventListener('wheel', eventListeners.wheel);
  }
}
