import { Constants } from 'chessboard/renderers/webgl/base/constants';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Resizes the board.
 */
export function resize<T extends WebGLRenderer.State>(instance: WebGLRenderer.Instance<T>): void {
  const { state, methods } = instance;
  const { width, height } = state.containerEl.getBoundingClientRect();

  state.viewSize.width = width || Constants.Board.DefaultWidth;
  state.viewSize.height = height || Constants.Board.DefaultHeight;

  methods.updateViewSize(state, state.viewSize);
}
