import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { removeEventListeners } from 'chessboard/renderers/webgl/base/listeners/remove-event-listeners';

/**
 * Destroy the renderer.
 */
export function destroy<T extends WebGLRenderer.State>(instance: WebGLRenderer.Instance<T>): void {
  const { className, frameRequestId, state, methods } = instance;
  const { animator, containerEl, viewEl } = state;

  state.destroyed = true;

  animator.endAll();

  if (frameRequestId) {
    cancelAnimationFrame(frameRequestId);
  }

  methods.destroy(state);

  removeEventListeners(instance);

  viewEl.parentNode?.removeChild(viewEl);
  containerEl.classList.remove(className);
}
