import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Fade the pieces setup.
 */
export function fadeSetup<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  fadeDuration: number,
): void {
  const { state, methods } = instance;
  const { animator } = state;

  if (state.fadeSetupAnimation) {
    animator.end(state.fadeSetupAnimation);
  }

  if (fadeDuration === 0) {
    return;
  }

  state.fadeSetupAnimation = methods.fadeInAllPieces(state, fadeDuration);
  state.fadeSetupAnimation.onEnd(() => (state.fadeSetupAnimation = null));
}
