import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Add the analysis overlay.
 */
export function addAnalysisOverlay<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
): void {
  const { state, methods } = instance;

  methods.addAnalysisOverlay(state);
}
