import type { Board } from 'chessboard/model/board/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import {
  positionToSquare,
  positionToSquarePercentage,
} from 'chessboard/renderers/webgl/base/utils';
import { getBoardXYFromEvent } from 'src/utils/get-board-xy-from-event';

/**
 * Get all the coordinates and squares needed to interact with the board.
 */
export function getPointerPosition<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  event: MouseEvent,
): Board.PointerPosition {
  const { state, methods } = instance;
  const { containerEl } = state;

  const coords = <Board.Coords>getBoardXYFromEvent(event, containerEl);

  const viewPosition = methods.normalizePointer(state, coords);
  const boardPosition = methods.getBoardPosition(state, viewPosition);
  const positionInsideBoard = methods.positionToNearestSquare(state, boardPosition);

  return {
    coords: viewPosition,
    coordsInsideBoard: methods.getViewPosition(state, positionInsideBoard),
    coordsInsideSquare: positionToSquarePercentage(boardPosition, state.squareSize),
    square: positionToSquare(instance, boardPosition),
    squareInsideBoard: positionToSquare(instance, positionInsideBoard),
  };
}
