/**
 * Easing functions based on Robert Penner's equations.
 * (copied from tween.js: https://github.com/tweenjs/tween.js)
 *
 * http://robertpenner.com/easing
 *
 * t: normalized time
 */

/**
 * Quadratic easing in.
 */
export function easeInQuadratic(t: number): number {
  return t * t;
}

/**
 * Quadratic easing out.
 */
export function easeOutQuadratic(t: number): number {
  return t * (2 - t);
}

/**
 * Quadratic easing in/out.
 */
export function easeInOutQuadratic(t: number): number {
  if ((t *= 2) < 1) {
    return 0.5 * t * t;
  }

  return -0.5 * (--t * (t - 2) - 1);
}
