import type { Board } from 'chessboard/model/board/types';
import { Game } from 'chessboard/model/game/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { swapPiece } from 'chessboard/renderers/webgl/base/pieces';
import { movePieces } from 'chessboard/renderers/webgl/base/pieces/move-pieces';
import { removePiece } from 'chessboard/renderers/webgl/base/pieces/remove-piece';
import { addPiece } from 'chessboard/renderers/webgl/base/pieces/add-piece';
import { getUndoMoveDetails } from 'chessboard/renderers/model/get-undo-move-details';
import { animatePiece, endAllPiecesAnimation } from 'chessboard/renderers/webgl/base/animation';
import { isCheckmate } from 'chessboard/model/move/is-checkmate';

/**
 * Undo the last move.
 */
export function undoMove<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    move,
    attackedKingSquare,
  }: {
    move: Game.Move.ExtendedNode;
    attackedKingSquare?: Board.SanSquare;
  },
): void {
  const { state, animationMethods } = instance;
  const { pieces } = state;
  const { movedPieces, restoredPiece, promotedSquare } = getUndoMoveDetails(move);

  endAllPiecesAnimation(state);

  if (move.drop) {
    removePiece(instance, { square: move.to });

    return;
  }

  state.attackedKing = attackedKingSquare ? pieces[attackedKingSquare] : null;
  state.isCheckmate = isCheckmate(move);

  movePieces(instance, <Game.Move.Extended[]>movedPieces);

  if (restoredPiece) {
    const addedPiece = addPiece(instance, restoredPiece);

    if (animationMethods.restorePiece) {
      animatePiece(instance, {
        animation: animationMethods.restorePiece(state, addedPiece),
        type: WebGLRenderer.Piece.Animation.Type.Restore,
        piece: addedPiece,
      });
    }
  }

  if (promotedSquare) {
    const promotedPiece = pieces[promotedSquare];

    swapPiece(instance, { piece: promotedPiece, type: Game.Piece.Types.Pawn });
  }
}
