import type { Board } from 'model/board/types';
import { WebGLRenderer } from 'chessboard/renderers/webgl/base';
import { animatePiece, endPieceAnimation } from 'chessboard/renderers/webgl/base/animation';

/**
 * Remove a piece from the board.
 */
export function removePiece<T extends WebGLRenderer.State>(
  instance: WebGLRenderer.Instance<T>,
  {
    captured,
    fromDrop,
    square,
  }: {
    captured?: boolean;
    fromDrop?: boolean;
    square: Board.SanSquare;
  },
): void {
  const { state, methods, animationMethods } = instance;
  const { pieces } = state;

  const piece = state.pieces[square];

  if (!piece) {
    return;
  }

  endPieceAnimation(state, piece);

  if (captured && animationMethods.capturePiece) {
    animatePiece(instance, {
      animation: animationMethods.capturePiece(state, { fromDrop, piece }),
      type: WebGLRenderer.Piece.Animation.Type.Capture,
      piece,
      onEnd: () => methods.removePiece(state, piece),
    });
  } else {
    methods.removePiece(state, piece);
  }

  delete pieces[square];

  if (state.selectedPiece === piece) {
    state.selectedPiece = null;
  }
}
