import type { Animator } from 'chessboard/renderers/model/animator/types';
import type { WebGLRenderer } from 'chessboard/renderers/webgl/base';

/**
 * Animate an item.
 *
 * The purpose of animating an item on the board through this function
 * is to make sure only one animation is playing for it.
 */
export function animateItem<T extends WebGLRenderer.State>(
  state: T,
  {
    item,
    animation,
    type,
    onEnd,
  }: {
    item: { activeAnimation?: WebGLRenderer.ItemAnimation.Model };
    animation: Animator.Animation.Model;
    type: WebGLRenderer.ItemAnimation.Type;
    onEnd?: Animator.Animation.Callback;
  },
): void {
  const { animator } = state;

  if (item.activeAnimation) {
    animator.end(item.activeAnimation.animation);
  }

  item.activeAnimation = { animation, type };

  animation.onEnd(() => {
    onEnd?.(animation);

    item.activeAnimation = undefined;
  });
}
